var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"커억......! 헉......! 허억......!","JPN":"ガハッ……！　くっ……！　ぐは……！","ENG":"Ack! Hngh! Huff!","TWN":"呃……！咳……！咳……！"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"숨이...... 안 쉬어져......","JPN":"息が……できない……","ENG":"I can't... breathe...","TWN":"我……不能呼吸……"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"빌어먹을...... 어디서 이런...... 괴물 같은 꼬맹이가 나타나서......","JPN":"くそっ……どこからこんな……化け物みたいなガキが……","ENG":"Drat it... Where the hell did they find this little monster?","TWN":"該死……從哪裡冒出了……這種怪物……"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"일어나, 이 개자식아!","JPN":"起きろ、このカス野郎！","ENG":"Get up, you bastard!","TWN":"起來，狗東西！"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"크윽......","JPN":"くうっ……","ENG":"Hngh...","TWN":"嚇呃……"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"네가 여태까지 저지른 잘못들은 따지기도 지긋지긋해.","JPN":"お前がこれまで犯した過ちを問い詰める時間すら勿体ない。","ENG":"I can't even begin to list all the evils you've committed.","TWN":"你犯下的罪過太多，數也數不完。"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그러니 하나만 말해.","JPN":"だから一つだけ答えろ。","ENG":"So I'll just ask about one.","TWN":"所以你只需告訴我一件事情就可以。"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"어째서...... 어째서 내 가족들을 죽인 거야?","JPN":"どうして……どうして私の家族を殺した？","ENG":"Why... Why did you kill my family?","TWN":"為什麼……為什麼殺了我的家人？"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"죽였다고......? 큭...... 내가?","JPN":"殺したって？　クク……俺が？","ENG":"I killed... who? Hah... Me?","TWN":"殺了你家人……？咳……我？"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"시치미 떼지 마!","JPN":"しらばっくれるな！","ENG":"Don't play dumb with me!","TWN":"別裝蒜！"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"집이 불타던 그날 똑똑히 봤어! 시간이 지났다고 내가 잊을 줄 알았냐?!","JPN":"家が燃えたあの日、この目で見た！　時間が経ったからって忘れたとでも思ったのか？","ENG":"I saw you that day when my house was on fire! Did you think I'd forget it after all these years?","TWN":"房子被燒的那天，我看得一清二楚！你以為時間會洗掉我的記憶嗎？！"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"집이 불타......? 대체 무슨 소리를......","JPN":"家が燃える……？　いったい何のこと……","ENG":"Fire? What house? What the hell are you talking about—","TWN":"房子被燒……？到底在說什麼……"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"아, 하핫......! 하하하하핫!","JPN":"ああ、ハハ！　アハハハハ！","ENG":"Oh... Hah hah... Hah hah hah hah!","TWN":"啊，哈哈……！哈哈哈哈哈！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"크큭, 끝내 주는군......! 정말, 쿨럭!! 끝내 줘......!","JPN":"ククク、最高だな……！　実に、ゲホッ！！　笑わせてくれる……！","ENG":"Hah, Incredible... This is really... *Cough*... incredible!","TWN":"咳咳，棒極了……！真的，咳咳！！棒極了……！"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"웃지 마! 내 질문에 대답해!","JPN":"笑ってんじゃない！　質問に答えろ！","ENG":"Stop laughing and answer me!","TWN":"別笑！快回答我！"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"아, 그래. 그 꼬마였군. 기억나.","JPN":"ああ、そうか。あの時のお嬢ちゃんか。思い出した。","ENG":"Ah, I see. So you were that little kid. I remember now.","TWN":"啊，沒錯。我記得，原來是那個小孩。"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"하지만 완전히 잘못 짚었다, 꼬마야.","JPN":"しかし勘違いしてるぞ、ガキ。","ENG":"But you've got it all wrong, little one.","TWN":"但你找錯人了，孩子。"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"이 아저씨는 그 때 그냥 지나가는 길이었거든.","JPN":"このおじさんはな、あの時たまたま通りかかっただけだ。","ENG":"I just happened to be walking by at the time.","TWN":"叔叔我當時只是路過而已。"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"뭐......?","JPN":"何……？","ENG":"What?","TWN":"什麼……？"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"방금 뭐라고 했어......?","JPN":"今、なんて……？","ENG":"What did you just say?","TWN":"你說什麼……？"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"그냥 지나가는 길이었다고. 네 녀석의 가족에겐 아무 짓도 안 했어.","JPN":"タダの通りすがりだったのさ。お前らの家族には何もしていない。","ENG":"I was just walking by. I didn't do anything to your family.","TWN":"我只是路過，我對妳的家人什麼也沒做。"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"거짓말 하지 마!!","JPN":"嘘をつくな！！","ENG":"Don't lie!","TWN":"休想騙我！！"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"분명 불타는 집 안에서 네가 나에게 무서우냐고 말을 걸었잖아!","JPN":"燃える家の中で、お前が私に怖いのかと確かに聞いてきただろ！","ENG":"I remember you asking me if I was scared in the burning house!","TWN":"你在燃燒的屋子裡，問過我怕不怕你！"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"......멀쩡한 집에서 갑자기 불꽃이 솟아오르길래 호기심에 들어가 본 거지.","JPN":"……なんの異変もなかった家が急に燃え出したから、好奇心が湧いて入ってみただけだ。","ENG":"I was just curious why the house would suddenly catch on fire, so I took a peek.","TWN":"……我只是好奇房子突然發生火災才進去的。"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"왜 내가 이런 설명을 하고 있는지 모르겠군.","JPN":"なんで俺がこんな説明をしなきゃいけないのかわからないね。","ENG":"I don't even know why I have to explain myself like this.","TWN":"我也不知道為什麼要對妳說明這些事。"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"너 설마...... 기억이 나지 않는 거냐?","JPN":"お前まさか……思い出せないのか？","ENG":"Wait... You don't remember anything, do you?","TWN":"妳難道……忘了嗎？"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"말 돌리지 마! 네가 하지 않았다면 누가 했다는 거야!","JPN":"とぼけるな！　お前じゃなきゃ誰があんなことを！","ENG":"Don't change the subject! If you didn't do it, who else could it be?","TWN":"別轉移話題！如果不是你，那到底是誰！"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"누가 우리 집에 불을 내고! 부모님을 죽였냐고!","JPN":"誰が家に火をつけて！　両親を殺したのか聞いてるんだ！","ENG":"Who else could have set my house on fire and killed my parents?","TWN":"誰在我們家放了火！殺了我的父母！"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"글쎄...... 혹시 너 아니냐?","JPN":"さあな……もしかしたらお前なんじゃないか？","ENG":"I don't know... Maybe it was you?","TWN":"會不會是……妳自己？"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"네가 믿든 말든...... 그 날 내가 집 안팎에서 본 사람은 너 한 명뿐이야.","JPN":"お前が信じようが信じまいが……あの日、俺が家の付近で合った人間はお前一人だけだ。","ENG":"Whether you believe me or not... You're the only person I saw there that day.","TWN":"信不信由妳……那天，我在你們家附近遇到的只有妳一個人而已。"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"닥쳐! 내가 왜 집에 불을 질러!","JPN":"黙れ！　私が家に火をつけるわけないだろう！","ENG":"Shut up! Why would I set my own home on fire?","TWN":"閉嘴！我為什麼會在我們家放火！"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"그래? 그럼 네 팔에 그 불길은 뭐냐?","JPN":"そうか？　じゃあ、お前のその腕の炎はなんだ？","ENG":"Oh, yeah? Then how would you explain the flames on your arms?","TWN":"是嗎？那妳手臂上的火焰又是怎麼回事？"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"처음 각성한 카운터들은 가끔 자기 힘을 주체 못하기도 하지.","JPN":"初めて覚醒したカウンターは、稀に自分の力を制御できないことがある。","ENG":"Sometimes Counters can't control their own power when they get it for the first time.","TWN":"首次覺醒的制裁者的力量往往會失控。"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"경력자 말을 믿으라고, 신참 카운터.","JPN":"先輩の言うことを信じろよ、新米カウンターくん。","ENG":"Trust me on this, rookie Counter.","TWN":"相信我這個過來人說的話吧，新人制裁者。"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"아냐......","JPN":"違う……","ENG":"No...","TWN":"不……"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"하지만 자기 가족을 숯덩이로 만들어 놓고 남한테 화풀이라니......","JPN":"しかし自分の家族を炭にしておいて、他人に八つ当たりだとは……","ENG":"Still, I can't believe you'd blame me after turning your own family to ashes...","TWN":"明明是自己燒死了家人，如今卻對我發火……"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"하하하하핫!! 아무리 나라도 이건 좀 우습군.","JPN":"ガハハハハッ！！　いくら俺でもこれは笑うしかないな。","ENG":"Hah hah hah! That's a new low, even for me!","TWN":"哈哈哈哈哈！！連我都覺得可笑。"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"아니라고!!","JPN":"違う！！","ENG":"You're wrong!","TWN":"不！！"},"stage":{"bg":"SS_MILITIA_08","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"크아아아악!","JPN":"ぐああああっ！！！！","ENG":"Aaargh!","TWN":"啊啊啊啊啊！"},"stage":{"bg":"BLACK","bgm":"THEMA_MILITIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_EXPLOSION_FIRE_BIG_04"},{"id":"L3_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"아니야......","JPN":"違う……","ENG":"No...","TWN":"不是這樣的……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"거짓말이야. 다 저놈이 멋대로 지껄인 소리야. 전부 다......!","JPN":"嘘だ。全部あいつが勝手にほざいてるだけ。全部嘘だ……！","ENG":"It's all a lie... Every word he said... all of it!","TWN":"騙人，都是他編出來的謊言，全部都是……！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"미안...... 미안해, 엄마...... 아빠......","JPN":"ごめん……ごめんね、お母さん……お父さん……","ENG":"I’m... sorry... I’m so sorry... Mom... Dad...","TWN":"對不起……對不起，媽媽……爸爸……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......그만둬.","JPN":"……やめろ。","ENG":"Enough.","TWN":"……住手。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......어?","JPN":"……え？","ENG":"Huh?","TWN":"……咦？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"네가 한 일이 아니라며. 그런데 왜 총을 머리통에 겨누고 있는 거냐?","JPN":"お前はやってないだろう。なのになぜ銃口を頭に向けるんだ？","ENG":"You said you didn't do it. So why do you have a gun pointed at your head?","TWN":"不是妳做的，為什麼還要拿槍瞄準自己的頭？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장......? 살아 있었어?","JPN":"隊長……？　生きていたのか？","ENG":"Captain? You're alive?","TWN":"隊長……？你沒死？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"요즘 자동차는 에어백 성능이 좋군.","JPN":"最新の車はエアバッグの性能がいいな。","ENG":"Those airbags work pretty good these days.","TWN":"多虧了汽車的安全氣囊。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"온 몸이 쑤시긴 하지만...... 그래, 살아 있다.","JPN":"全身あちこち痛いが……そう、生きている。","ENG":"I'm sore all over... but yeah, I'm alive.","TWN":"雖然渾身難受……但至少保住了性命。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장! 다행이야......","JPN":"隊長！　よかった……","ENG":"Captain! Thank goodness...","TWN":"隊長！太好了……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"하지만...... 하지만 난 살인자인데......","JPN":"でも……でも、私は人殺しなんだ……","ENG":"But... But I'm a murderer...","TWN":"可是……我是個殺人犯……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"말했잖아. 네가 한 일이 아니라고.","JPN":"言っただろ。お前はやっていない。","ENG":"Like I said, there's no proof it was you.","TWN":"妳不是說了嗎，不是妳幹的。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"정황 증거 따위에 너무 마음을 뺏기지 마.","JPN":"状況証拠なんかに惑わされるな。","ENG":"Don't let circumstantial evidence get to your head.","TWN":"不要太在意旁證。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그런 건 언제든지 뒤집힐 수 있다는 걸 경찰 시절에 지긋지긋하게 봤거든.","JPN":"そんなものはいくらでもひっくり返るってことを、警察時代にうんざりするほど見てきたんだ。","ENG":"I've seen that get overturned all the time when I used to be a cop.","TWN":"我當員警時接觸過不少沒意義的旁證。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"하지만......","JPN":"でも……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"모르지, 그저 단순한 실화였을 수도. 아니면 다른 범죄자의 소행이었을 수도......","JPN":"わからないさ。単純な事故だったかもしれないし、他の犯罪者の仕業かもしれない……","ENG":"You never know. It could have been just an accidental fire. Or maybe there's another arsonist...","TWN":"誰知道呢，也許是單純的失火，也許是另一個犯罪者幹的。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그러니까 미리 자신에게 유죄를 선고하고 집행하지 마.","JPN":"だから、先走って自分を有罪と決めつけて執行するなってことだ。","ENG":"So don't jump to conclusions and sentence yourself to death.","TWN":"所以不要急於向自己宣告有罪。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그런 건 정말 진실이 밝혀진 후에 결정해도 돼.","JPN":"そんなことは真実が明らかになった後に決めればいい。","ENG":"That can wait until you have the full truth.","TWN":"等真相大白後再決定也不遲。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"지금은......","JPN":"今は……","ENG":"For now...","TWN":"現在的話……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그래, 지금은 그저 이 말이 어울리겠군.","JPN":"そうだな、今はこの言葉が相応しいだろう。","ENG":"Yes, for now, I think these words are more apt.","TWN":"對，現在的話，我只想對妳說這一句。"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"고생했다. 이유리.","JPN":"ご苦労様だ、カスカベ・ユリ。","ENG":"Good work, Yuri.","TWN":"辛苦了，李悠麗。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};